sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading)
        return;

    // Clear Category & Subcategory
    g_form.clearOptions('servicenow_category');
    g_form.setValue('servicenow_category', '');
    g_form.clearOptions('servicenow_sub_category');
    g_form.setValue('servicenow_sub_category', '');

    if (!newValue)
        return;

    // Placeholder
    g_form.addOption('servicenow_category', '', '-- Select Category --');

    var ga = new GlideAjax('PulseCategoryAjax');
    ga.addParam('sysparm_name', 'getCategories');
    ga.addParam('sysparm_table', newValue);

    ga.getXMLAnswer(function (answer) {
        if (!answer)
            return;

        var categories = JSON.parse(answer);
        for (var i = 0; i < categories.length; i++) {
            g_form.addOption(
                'servicenow_category',
                categories[i].value,
                categories[i].label
            );
        }
    });
}
